// Тест методов массивов
const numbers = [1, 2, 3, 4, 5];

// forEach для вывода каждого элемента
numbers.forEach(function(num) {
  console.log('Элемент: ' + num);
});
// Вывод: Элемент: 1, Элемент: 2 и т.д.

// map для возведения в квадрат каждого элемента
const squares = numbers.map(function(num) {
  return num * num;
});
console.log(squares); // [1, 4, 9, 16, 25]

// filter для выбора нечетных чисел
const odds = numbers.filter(function(num) {
  return num % 2 !== 0;
});
console.log(odds); // [1, 3, 5]

// reduce для суммирования всех элементов
const sum = numbers.reduce(function(acc, num) {
  return acc + num;
}, 0);
console.log(sum); // 15

// find для поиска первого элемента больше 3
const firstLarge = numbers.find(function(num) {
  return num > 3;
});
console.log(firstLarge); // 4
